{"version":3,"sourceRoot":"","sources":["style.scss"],"names":[],"mappings":";AAAA;AAAA;AAAA;AAIA;AAAA;AAAA;AAAA;AAAA;AAMA;AACA;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EAEA;EACA;EACA;EACA;EAEA;EACA;EACA;EACA;EACA;EAEA;EACA;EACA;EACA;EAEA;EACA;;;AAGF;AACA;EACE;;;AAGF;EACE;AACA;AAAA;AAAA;AAAA;AAIA;AAAA;;;AAIF;EACE;IACE;;;AAIJ;EACE;EACA;EACA;EACA;EACA;EACA;AACA;AAAA;AAAA;EAGA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;;;AAGF;AACA;EACE;EACA;EACA;EACA;EACA;AACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;AACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;AACA;EACA;;;AAGF;AACA;EACE;IACE;IACA;IACA;;EAGF;IACE;IACA;;EAGF;IACE;IACA;;;AAIJ;AACA;EACE;IACE;;EAEF;IACE;;;AAIJ;AACA;EACE;IACE;IACA;;EAEF;IACE;IACA;;;AAIJ;EACE;IACE;;EAEF;IACE;;EAEF;IACE;;;AAIJ;EACE;IACE;;EAEF;IACE;;;AAIJ;AAAA;AAAA;AAAA;AAAA;AAAA;AAMA;AACE;EACA;EACA;EACA;;;AAGF;AACA;EACE;IACE;IACA;IACA;;AAGF;EACA;IACE;;;AAIJ;EACE;;;AAGF;EACE;IACE;;;AAIJ;EACE;EACA;EACA;;;AAGF;AAAA;AAEA;EACE;;;AAGF;EACE;IAAO;;EACP;IAAK;;;AAGP;AACA;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;AACA;EACE;EACA;EACA;EACA;EACA;EACA;AACA;AAAA;AAAA;AAAA;AAAA;EAKA;;;AAGF;AACA;EACE;EACA;AACA;;;AAGF;EACE;IACE;;;AAIJ;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;AACA;EACE;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;AACA;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;AACA;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;;;AAGF;AACA;AACA;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;AACA;;;AAGF;EACE;IACE;;EAGF;IACE;IACA;IACA;;;AAIJ;AAAA;AAEA;EACE;IACE;;;AAIJ;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;AACA;AACA;AAAA;EAEE;;AAEA;AAAA;EAAkB;;AAClB;AAAA;EAAmB;EAAiB;;AACpC;AAAA;EAAqB;;AACrB;AAAA;EAAqB;EAAsB;;AAC3C;AAAA;EAAkB;;AAClB;AAAA;EAAY;EAAqB;;;AAGnC;EACE;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;AACA;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;;;AAGF;AACA;EACE;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;AACA;EACE;EACA;EACA;AACA;AAAA;AAAA;AAAA;EAIA;;;AAGF;EACE;;;AAGF;AAAA;AAAA;AAAA;EAIE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;AAAA;EAEE;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;AAAA;EAEE;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;AAAA;EAEE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA,YACE;;;AAIJ;AAAA;EAEE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;;;AAGF;AAAA;EAEE;EACA;EACA;EACA;EACA;;;AAGF;AACA;EACE;EACA;EACA;EACA;EACA;EACA;EACA;AACA;AAAA;AAAA;EAGA;;;AAGF;EACE;EACA;EACA;AACA;AAAA;EAEA;EACA;EACA;EACA;EACA;AACA;;;AAGF;AACA;EACE;IACE;;;AAIJ;EACE;;;AAGF;AACA;EACE;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;AACA;EACE;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;AAAA;EAEE;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;IACE;;;AAIJ;AAAA;AAAA;AAAA;AAAA;AAAA;EAME;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;AAAA;AAAA;EAGE;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;AAAA;AAAA;AAGA;EACE;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;IACA;IACA;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;;AAGF;AAAA;EAEA;IACE;IACA;IACA;IACA;IACA;IACA;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;IACA;IACA;;EAGF;AAAA;IAEE;;EAEA;AAAA;IAAkB;;EAClB;AAAA;IAAmB;IAAmB;;EACtC;AAAA;IAAqB;;EACrB;AAAA;IAAqB;IAAsB;;EAC3C;AAAA;IAAkB;;EAClB;AAAA;IAAY;IAAoB;;EAGlC;IACE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;AAAA;IAEE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;;AAIJ;AAAA;AAAA;AAGA;EACE;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;AAAA;IAEE;IACA;;EAGF;IACE;IACA;;;AAIJ;AACA;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;;AAIJ;EACE;IACE;IACA;;EAGF;IACE;;;AAIJ;AACA;EACE;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;EACE;;;AAGF;EACE;EACA;EACA;EACA;EACA;;;AAGF;EACE;EACA;;;AAGF;EACE;EACA;EACA;;;AAGF;EACE;IACE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;IACA;IACA;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;IACA;IACA;;EAGF;IACE;IACA;;EAGF;IACE;IACA;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;;EAGF;IACE;IACA;;;AAIJ;EACE;IACE;;EAGF;IACE;;;AAIJ;AAAA;AAAA;AAAA;AAIA;EACE;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;IAWE;;;AAIJ;AACA;EACE;AAAA;AAAA;IAGE;IACA;IACA;IACA;;EAGF;IACE;IACA;;;AAIJ;AAAA;AAAA;AAAA;AAAA;AAKA;EACE;;;AAEF;EACE;;;AAEF;EAAiB;EAAa;;;AAC9B;EAAkB;EAAgB;;;AAClC;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;EAAa;;;AAC9B;EAAiB;EAAa;;;AAC9B;EAAiB;EAAa;;;AAC9B;EAAiB;EAAa;EAAmB;;;AACjD;EAAiB;EAAa;;;AAC9B;EAAoB;EAAa;;;AACjC;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;EAAa;;;AAC9B;EAAoB;EAAa;;;AACjC;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;EAAa;;;AAC9B;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;EAAa;;;AAC9B;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;EAAa;;;AAC9B;EAAiB;EAAa;;;AAC9B;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB;;;AACjB;EAAiB","sourcesContent":["/* minima CSS fully removed — @import and async <link> both dropped.\n   Syntax highlighting (.highlight) rules are now inlined at the bottom of this file.\n   This eliminates the need for any external minima CSS dependency. */\n\n/* <span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class="post-highlight">=\n   Theme: Modern Minimalist Blog\n   Palette: Emerald Green\n   Mobile First\n   &lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;</span>= */\n\n/* ---------- CSS Variables ---------- */\n:root {\n  --color-primary: #028760;\n  --color-primary-light: #34d399;\n  --color-primary-dark: #047857;\n  --color-accent: #10b981;\n  --color-accent-light: #6ee7b7;\n  --color-bg: #f8fafc;\n  --color-surface: #ffffff;\n  --color-surface-alt: #f1f5f9;\n  --color-text: #1e293b;\n  --color-text-secondary: #334155;\n  --color-text-muted: #64748b;\n  --color-border: #e2e8f0;\n  --color-border-light: #f1f5f9;\n  --color-code-bg: #1e1e2e;\n  --color-code-red: #ff5f56;\n  --color-code-yellow: #ffbd2e;\n  --color-code-green: #27c93f;\n\n  --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.04);\n  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.06), 0 2px 4px -2px rgb(0 0 0 / 0.04);\n  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.08), 0 4px 6px -4px rgb(0 0 0 / 0.04);\n  --shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.08), 0 8px 10px -6px rgb(0 0 0 / 0.04);\n\n  --radius-sm: 8px;\n  --radius-md: 12px;\n  --radius-lg: 16px;\n  --radius-xl: 24px;\n  --radius-full: 9999px;\n\n  --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);\n  --transition-base: 300ms cubic-bezier(0.4, 0, 0.2, 1);\n  --transition-slow: 500ms cubic-bezier(0.4, 0, 0.2, 1);\n  --transition-bounce: 400ms cubic-bezier(0.34, 1.56, 0.64, 1);\n\n  --content-max-width: 720px;\n  --page-padding: 1rem;\n}\n\n/* ---------- Base & Reset ---------- */\n*, *::before, *::after {\n  box-sizing: border-box;\n}\n\nhtml {\n  -webkit-text-size-adjust: 100%;\n  /* overflow-x: hidden REMOVED — on mobile, this breaks the compositor's fast\n     scrolling path by forcing the main thread to check overflow clipping on every\n     touch-move event, causing \"scroll not keeping up with finger\" lag.\n     Instead, we prevent horizontal overflow at the body level with clip. */\n  /* scroll-behavior: smooth moved to desktop-only — on mobile it forces\n     the main thread to compute smooth scroll positions during touch-driven scrolling */\n}\n\n@media (min-width: 768px) {\n  html {\n    scroll-behavior: smooth;\n  }\n}\n\nbody {\n  font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, \"Helvetica Neue\", Arial, \"Noto Sans SC\", \"PingFang SC\", \"Microsoft YaHei\", sans-serif;\n  background: var(--color-bg);\n  color: var(--color-text);\n  line-height: 1.7;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n  /* Prevent horizontal overflow without breaking fast scroll path.\n     clip creates a clip region but does NOT create a new scroll container,\n     so the compositor thread can still handle scrolling autonomously. */\n  overflow-x: clip;\n}\n\na {\n  color: var(--color-primary);\n  text-decoration: none;\n  transition: color var(--transition-fast);\n}\n\na:hover {\n  color: var(--color-primary-dark);\n}\n\nimg {\n  max-width: 100%;\n  height: auto;\n  display: block;\n}\n\n/* ---------- Background Decorative Shapes ---------- */\n.bg-shape {\n  position: fixed;\n  border-radius: 50%;\n  opacity: 0.35;\n  pointer-events: none;\n  z-index: 0;\n  /* Mobile: no blur, no will-change — zero GPU overhead */\n}\n\n.bg-shape-1 {\n  width: 50vw;\n  height: 50vw;\n  max-width: 500px;\n  max-height: 500px;\n  background: var(--color-primary-light);\n  top: -10%;\n  right: -15%;\n  /* Mobile fallback: low-opacity solid color, no blur */\n  opacity: 0.08;\n}\n\n.bg-shape-2 {\n  width: 40vw;\n  height: 40vw;\n  max-width: 400px;\n  max-height: 400px;\n  background: var(--color-accent-light);\n  bottom: 5%;\n  left: -10%;\n  /* Mobile fallback: low-opacity solid color, no blur */\n  opacity: 0.08;\n}\n\n/* Desktop+: upgrade to blur + gradient + will-change */\n@media (min-width: 768px) {\n  .bg-shape {\n    filter: blur(40px);\n    will-change: transform;\n    opacity: 0.35;\n  }\n\n  .bg-shape-1 {\n    background: radial-gradient(circle, var(--color-primary-light) 0%, transparent 70%);\n    opacity: 0.35;\n  }\n\n  .bg-shape-2 {\n    background: radial-gradient(circle, var(--color-accent-light) 0%, transparent 70%);\n    opacity: 0.35;\n  }\n}\n\n/* Only animate on tablet+ AND only when user hasn't opted for reduced motion */\n@media (min-width: 768px) and (prefers-reduced-motion: no-preference) {\n  .bg-shape-1 {\n    animation: float 18s ease-in-out infinite;\n  }\n  .bg-shape-2 {\n    animation: float 22s ease-in-out infinite reverse;\n  }\n}\n\n/* ---------- Keyframes ---------- */\n@keyframes fadeInUp {\n  from {\n    opacity: 0;\n    transform: translateY(24px);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n@keyframes float {\n  0%, 100% {\n    transform: translate(0, 0) scale(1);\n  }\n  33% {\n    transform: translate(20px, -30px) scale(1.05);\n  }\n  66% {\n    transform: translate(-15px, 15px) scale(0.95);\n  }\n}\n\n@keyframes arrow-bounce {\n  0%, 100% {\n    transform: translateX(0);\n  }\n  50% {\n    transform: translateX(4px);\n  }\n}\n\n/* ---------- Scroll Reveal Utilities ----------\n   Mobile strategy: content is immediately visible (opacity:1), no transform, no transition.\n   This prevents the \"white screen\" where the browser finishes Layout+Paint but content\n   is hidden behind opacity:0, waiting for IntersectionObserver to fire — the #1 cause\n   of perceived lag on first load. A subtle fade-in is applied via JS after initial paint.\n   Desktop: full reveal animation with translateY slide. */\n.reveal {\n  /* Mobile-first: content visible immediately, zero transition cost on first paint */\n  opacity: 1;\n  transform: none;\n  transition: none;\n}\n\n/* Desktop+: enable slide-up reveal animation */\n@media (min-width: 768px) {\n  .reveal {\n    opacity: 0;\n    transform: translateY(28px);\n    transition: opacity 0.55s var(--transition-base), transform 0.55s var(--transition-base);\n  }\n\n  /* Desktop masonry (column-count): transform triggers column rebalancing, so use opacity-only fade */\n  .post-grid .reveal {\n    transform: none;\n  }\n}\n\n.reveal.is-transitioning {\n  will-change: opacity, transform;\n}\n\n@media (min-width: 768px) {\n  .post-grid .reveal.is-transitioning {\n    will-change: opacity;\n  }\n}\n\n.revealed {\n  opacity: 1;\n  transform: none;\n  will-change: auto;\n}\n\n/* Mobile fade-in class: applied by JS after first paint for subtle entrance.\n   Uses opacity-only (no transform) to avoid any layout recalculation. */\n.reveal.is-fading-in {\n  animation: revealFadeIn 0.4s ease-out both;\n}\n\n@keyframes revealFadeIn {\n  from { opacity: 0.6; }\n  to { opacity: 1; }\n}\n\n/* ---------- Footer ---------- */\n.site-footer {\n  position: relative;\n  z-index: 1;\n  margin-top: 1.25rem;\n  padding: 1rem var(--page-padding) !important;\n  border-top: 1px solid var(--color-border-light);\n}\n\n.footer-content {\n  max-width: var(--content-max-width);\n  margin: 0 auto;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 0.75rem;\n}\n\n.footer-links {\n  display: flex;\n  align-items: center;\n  gap: 0.75rem;\n}\n\n.footer-links a {\n  font-size: 0.875rem;\n  font-weight: 500;\n  color: var(--color-text-secondary);\n  transition: color var(--transition-fast);\n}\n\n.footer-links a:hover {\n  color: var(--color-primary);\n}\n\n.footer-dot {\n  font-size: 0.875rem;\n  color: var(--color-border);\n  user-select: none;\n}\n\n.footer-copy {\n  font-size: 0.8125rem;\n  color: var(--color-text-muted);\n  margin: 0;\n}\n\n/* ---------- Page Content Wrapper ---------- */\n.page-content {\n  position: relative;\n  z-index: 1;\n  width: 100%;\n  max-width: var(--content-max-width);\n  margin: 0 auto;\n  padding: 1rem var(--page-padding) 0.5rem !important;\n  /* overflow-x: hidden REPLACED with clip — hidden creates a scroll container\n     which breaks the compositor's fast scrolling path on mobile, causing\n     touch-driven scrolling to go through the main thread (laggy, not keeping up).\n     clip clips overflow content but does NOT create a scroll container,\n     so the compositor can still handle scrolling autonomously on its own thread. */\n  overflow-x: clip;\n}\n\n/* ---------- Hero Section ---------- */\n.hero {\n  padding: 1rem 0 0.5rem;\n  text-align: center;\n  /* No animation on mobile — deferred to desktop to reduce first-paint cost */\n}\n\n@media (min-width: 768px) {\n  .hero {\n    animation: fadeInUp 0.7s ease-out both;\n  }\n}\n\n.hero-illustration {\n  display: block;\n  max-width: 160px;\n  width: 100%;\n  height: auto;\n  margin: 0 auto 0.75rem;\n}\n\n.hero-title {\n  font-size: 1.375rem;\n  font-weight: 800;\n  letter-spacing: -0.03em;\n  line-height: 1.2;\n  margin: 0 0 0.5rem;\n  background: linear-gradient(135deg, var(--color-text), var(--color-primary-dark));\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n}\n\n.hero-desc {\n  font-size: 0.8125rem;\n  color: var(--color-text-muted);\n  max-width: 480px;\n  margin: 0 auto;\n  line-height: 1.6;\n}\n\n.hero-divider {\n  width: 40px;\n  height: 3px;\n  margin: 0.75rem auto 0;\n  border-radius: var(--radius-full);\n  background: linear-gradient(90deg, var(--color-primary), var(--color-accent));\n  opacity: 0.6;\n}\n\n/* ---------- Tag Filter Bar ---------- */\n.tag-filter-bar {\n  display: flex;\n  align-items: center;\n  gap: 0;\n  margin: 0.75rem 0;\n  position: relative;\n  max-width: 100%;\n  overflow: hidden;\n}\n\n/* Gradient fade on right edge (hints more content) */\n.tag-filter-bar::before {\n  content: '';\n  position: absolute;\n  right: 1.75rem;\n  top: 0;\n  bottom: 0;\n  width: 1.5rem;\n  background: linear-gradient(90deg, transparent, var(--color-bg));\n  pointer-events: none;\n  z-index: 1;\n  transition: opacity var(--transition-fast);\n}\n\n.tag-filter-bar.is-expanded::before {\n  opacity: 0;\n}\n\n.tag-filter-inner {\n  display: flex;\n  flex-wrap: nowrap;\n  gap: 0.375rem;\n  overflow-x: auto;\n  scrollbar-width: none;\n  -ms-overflow-style: none;\n  flex: 1;\n  padding: 0.125rem 2rem 0.125rem 0;\n  overscroll-behavior-x: contain;    /* prevent pull-to-refresh from inner scroll */\n}\n\n.tag-filter-inner::-webkit-scrollbar {\n  display: none;\n}\n\n/* Expanded: show all tags wrapped */\n.tag-filter-bar.is-expanded .tag-filter-inner {\n  flex-wrap: wrap;\n  overflow-x: visible;\n  padding-right: 0;\n}\n\n.tag-filter-btn {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.1875rem;\n  font-size: 0.75rem;\n  font-weight: 500;\n  padding: 0.25rem 0.625rem;\n  border-radius: 8px;\n  border: none;\n  background: transparent;\n  color: var(--color-text-muted);\n  cursor: pointer;\n  white-space: nowrap;\n  transition: all var(--transition-fast);\n  line-height: 1.5;\n  flex-shrink: 0;\n}\n\n.tag-filter-btn:hover {\n  background: var(--color-surface-alt);\n  color: var(--color-text);\n}\n\n.tag-filter-btn.is-active {\n  background: var(--color-primary);\n  color: #fff;\n}\n\n.tag-filter-btn.is-active .tag-count {\n  color: rgba(255,255,255,0.75);\n}\n\n.tag-count {\n  font-size: 0.625rem;\n  font-weight: 400;\n  color: var(--color-text-muted);\n  opacity: 0.7;\n}\n\n.tag-filter-expand {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  width: 1.75rem;\n  height: 1.75rem;\n  flex-shrink: 0;\n  border: none;\n  border-radius: 8px;\n  background: transparent;\n  color: var(--color-text-muted);\n  cursor: pointer;\n  transition: all var(--transition-fast);\n  z-index: 2;\n  margin-left: -0.25rem;\n}\n\n.tag-filter-expand:hover {\n  background: var(--color-surface-alt);\n  color: var(--color-primary);\n}\n\n.tag-filter-bar.is-expanded .tag-filter-expand {\n  background: var(--color-surface-alt);\n}\n\n.expand-arrow {\n  font-size: 0.5625rem;\n  transition: transform var(--transition-base);\n  line-height: 1;\n}\n\n.tag-filter-bar.is-expanded .expand-arrow {\n  transform: rotate(180deg);\n}\n\n/* ---------- Post Columns & Cards (Mobile: Grid, Desktop: Masonry) ---------- */\n/* Mobile: CSS Grid 2-col — zero layout recalculation during scroll (column-count forces continuous rebalancing) */\n.post-grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 0.75rem;\n  margin-top: 0.75rem;\n  min-width: 0;\n  align-items: start;\n}\n\n.post-grid .post-card {\n  margin-bottom: 0;\n}\n\n.post-grid.is-single {\n  grid-template-columns: 1fr;\n}\n\n.post-card {\n  background: var(--color-surface);\n  border-radius: var(--radius-md);\n  border: 1px solid var(--color-border-light);\n  box-shadow: var(--shadow-sm);\n  overflow: hidden;\n  min-width: 0;\n  margin: 0;\n  /* No transition on mobile — transform/box-shadow only useful on hover (desktop) */\n}\n\n@media (min-width: 768px) {\n  .post-card {\n    transition: transform var(--transition-base), box-shadow var(--transition-base), border-color var(--transition-base);\n  }\n\n  .post-card:hover {\n    transform: translateY(-4px);\n    box-shadow: var(--shadow-xl);\n    border-color: rgba(2, 135, 96, 0.15);\n  }\n}\n\n/* active feedback on desktop only — on mobile, transform on active\n   causes layout recalculation during touch-driven scroll */\n@media (min-width: 768px) {\n  .post-card:active {\n    transform: translateY(-2px) scale(0.995);\n  }\n}\n\n.post-card-link {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  color: inherit;\n  padding: 0.875rem;\n}\n\n.post-card-link:hover {\n  color: inherit;\n}\n\n.post-card-body {\n  flex: 1;\n}\n\n.post-card-title {\n  font-size: 0.875rem;\n  font-weight: 700;\n  line-height: 1.35;\n  margin: 0 0 0.5rem;\n  color: var(--color-text);\n  transition: color var(--transition-fast);\n}\n\n.post-card:hover .post-card-title {\n  color: var(--color-primary-dark);\n}\n\n.post-card:hover .post-card-title .title-sub {\n  color: var(--color-primary-dark);\n}\n\n.title-sub {\n  font-weight: 400;\n  color: var(--color-text-muted);\n}\n\n.post-card-divider {\n  border: none;\n  height: 1px;\n  background: linear-gradient(90deg, rgba(2, 135, 96, 0.2), transparent 90%);\n  margin: 0 0 1rem;\n}\n\n.post-card-meta {\n  display: flex;\n  flex-wrap: nowrap;\n  align-items: center;\n  justify-content: space-between;\n  gap: 0.375rem;\n  margin-bottom: 0.625rem;\n  overflow: hidden;\n}\n\n.post-date {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.2rem;\n  font-size: 0.6875rem;\n  color: var(--color-text-muted);\n  flex-shrink: 0;\n}\n\n.meta-icon {\n  font-size: 0.75rem;\n  opacity: 0.9;\n}\n\n.post-tags {\n  display: flex;\n  flex-wrap: nowrap;\n  gap: 0.1875rem;\n  flex-shrink: 0;\n  overflow: hidden;\n}\n\n.tag-pill {\n  display: inline-block;\n  font-size: 0.5625rem;\n  font-weight: 600;\n  padding: 0.0625rem 0.3125rem;\n  border-radius: var(--radius-full);\n  background: rgba(2, 135, 96, 0.08);\n  color: var(--color-primary-dark);\n  border: 1px solid rgba(2, 135, 96, 0.12);\n  white-space: nowrap;\n  transition: background var(--transition-fast), color var(--transition-fast), transform var(--transition-fast);\n}\n\n.tag-pill:hover {\n  background: var(--color-primary);\n  color: #fff;\n  transform: scale(1.05);\n}\n\n.tag-pill--subtle {\n  background: var(--color-surface-alt);\n  color: var(--color-text-muted);\n  border-color: var(--color-border);\n}\n\n.tag-pill--subtle:hover {\n  background: var(--color-text-muted);\n  color: #fff;\n}\n\n.post-card-excerpt {\n  font-size: 0.75rem;\n  color: var(--color-text-muted);\n  line-height: 1.5;\n  margin: 0;\n  display: -webkit-box;\n  -webkit-line-clamp: 3;\n  -webkit-box-orient: vertical;\n  overflow: hidden;\n}\n\n/* ---------- Featured Post Card ---------- */\n/* Applied to: the standalone first card, and all grid cards in single-column mode */\n.post-card--featured,\n.post-grid.is-single .post-card {\n  margin: 0 0 0.75rem;\n\n  .post-card-link { padding: 1.125rem 1rem; }\n  .post-card-title { font-size: 1rem; margin-bottom: 0.5rem; }\n  .post-card-divider { margin-bottom: 1rem; }\n  .post-card-excerpt { font-size: 0.8125rem; -webkit-line-clamp: 4; }\n  .post-card-meta { margin-bottom: 0.625rem; }\n  .tag-pill { font-size: 0.625rem; padding: 0.125rem 0.375rem; }\n}\n\n.post-card-footer {\n  display: none;\n}\n\n.read-more {\n  font-size: 0.75rem;\n  font-weight: 600;\n  color: var(--color-primary);\n  display: inline-flex;\n  align-items: center;\n  gap: 0.25rem;\n  transition: gap var(--transition-fast);\n}\n\n.post-card:hover .read-more {\n  gap: 0.5rem;\n}\n\n.post-card:hover .arrow {\n  animation: arrow-bounce 0.8s ease-in-out infinite;\n}\n\n/* ---------- Empty State ---------- */\n.empty-state {\n  text-align: center;\n  padding: 2.5rem 1.25rem;\n  background: var(--color-surface);\n  border-radius: var(--radius-lg);\n  border: 2px dashed var(--color-border);\n  margin-top: 0.5rem;\n}\n\n.empty-illustration {\n  display: block;\n  max-width: 180px;\n  width: 100%;\n  height: auto;\n  margin: 0 auto 1rem;\n  opacity: 0.9;\n}\n\n.empty-title {\n  font-size: 1rem;\n  font-weight: 600;\n  color: var(--color-text-secondary);\n  margin: 0 0 0.375rem;\n}\n\n.empty-desc {\n  font-size: 0.8125rem;\n  color: var(--color-text-muted);\n  margin: 0;\n}\n\n.empty-desc code {\n  background: var(--color-surface-alt);\n  padding: 0.15rem 0.4rem;\n  border-radius: var(--radius-sm);\n  font-size: 0.75rem;\n  color: var(--color-primary-dark);\n}\n\n/* ---------- Post Article ---------- */\n.post {\n  position: relative;\n}\n\n.post-header {\n  padding: 1.5rem 0 0.75rem;\n  margin-bottom: 0.75rem;\n  border-bottom: 1px solid var(--color-border-light);\n}\n\n.post-title {\n  font-size: 1.75rem;\n  font-weight: 800;\n  line-height: 1.25;\n  letter-spacing: -0.02em;\n  margin: 0 0 1rem;\n  color: var(--color-text);\n}\n\n.post-meta {\n  display: flex;\n  flex-wrap: wrap;\n  align-items: center;\n  gap: 0.625rem 1rem;\n}\n\n/* ---------- Post Content Typography ---------- */\n.post-content {\n  font-size: 1rem;\n  line-height: 1.8;\n  color: var(--color-text-secondary);\n  /* CSS Containment: tells the browser this element's contents are independent\n     of the rest of the page, so it can skip style/layout recalculation for\n     outside elements when scrolling. Reduces per-frame work significantly\n     on long article pages. */\n  contain: content;\n}\n\n.post-content > *:first-child {\n  margin-top: 0;\n}\n\n.post-content h1,\n.post-content h2,\n.post-content h3,\n.post-content h4 {\n  color: var(--color-text);\n  font-weight: 700;\n  line-height: 1.35;\n  margin: 2.25rem 0 1rem;\n  letter-spacing: -0.01em;\n}\n\n.post-content h1 {\n  font-size: 1.5rem;\n  border-bottom: 1px solid var(--color-border-light);\n  padding-bottom: 0.5rem;\n}\n\n.post-content h2 {\n  font-size: 1.375rem;\n  position: relative;\n  padding-left: 0.875rem;\n}\n\n.post-content h2::before {\n  content: '';\n  position: absolute;\n  left: 0;\n  top: 0.35rem;\n  bottom: 0.35rem;\n  width: 4px;\n  border-radius: var(--radius-full);\n  background: linear-gradient(180deg, var(--color-primary), var(--color-accent));\n}\n\n.post-content h3 {\n  font-size: 1.125rem;\n}\n\n.post-content h4 {\n  font-size: 1rem;\n  color: var(--color-text-secondary);\n}\n\n.post-content p {\n  margin: 1.25rem 0;\n}\n\n.post-content blockquote {\n  margin: 1.5rem 0;\n  padding: 1rem 1.25rem;\n  border-left: 4px solid var(--color-primary);\n  border-radius: 0 var(--radius-md) var(--radius-md) 0;\n  background: rgba(2, 135, 96, 0.04);\n  color: var(--color-text-secondary);\n  font-style: italic;\n  font-size: 0.9375rem;\n  line-height: 1.7;\n}\n\n.post-content blockquote p:first-child {\n  margin-top: 0;\n}\n\n.post-content blockquote p:last-child {\n  margin-bottom: 0;\n}\n\n.post-content ul,\n.post-content ol {\n  margin: 1.25rem 0;\n  padding-left: 1.5rem;\n}\n\n.post-content li {\n  margin: 0.375rem 0;\n}\n\n.post-content li::marker {\n  color: var(--color-primary);\n}\n\n.post-content img {\n  border-radius: var(--radius-md);\n  margin: 1.5rem auto;\n  box-shadow: var(--shadow-md);\n  border: 1px solid var(--color-border-light);\n}\n\n.post-content table {\n  width: 100%;\n  border-collapse: collapse;\n  margin: 1.5rem 0;\n  font-size: 0.9375rem;\n  border-radius: var(--radius-md);\n  overflow: hidden;\n  box-shadow: var(--shadow-sm);\n  border: 1px solid var(--color-border);\n}\n\n.post-content thead {\n  background: var(--color-surface-alt);\n}\n\n.post-content th,\n.post-content td {\n  padding: 0.625rem 0.875rem;\n  text-align: left;\n  border-bottom: 1px solid var(--color-border-light);\n}\n\n.post-content th {\n  font-weight: 600;\n  color: var(--color-text);\n  font-size: 0.875rem;\n  text-transform: uppercase;\n  letter-spacing: 0.03em;\n}\n\n.post-content tbody tr:nth-child(even) {\n  background: rgba(241, 245, 249, 0.5);\n}\n\n.post-content tbody tr:last-child td {\n  border-bottom: none;\n}\n\n.post-content code {\n  font-family: \"SF Mono\", Monaco, \"Cascadia Code\", \"Roboto Mono\", Consolas, \"Courier New\", monospace;\n  font-size: 0.875em;\n  background: var(--color-surface-alt);\n  color: var(--color-primary-dark);\n  padding: 0.15em 0.4em;\n  border-radius: var(--radius-sm);\n  border: 1px solid var(--color-border-light);\n  word-break: break-word;\n}\n\n.post-content pre,\n.post-content .highlight {\n  position: relative;\n  background: var(--color-code-bg);\n  border-radius: var(--radius-md);\n  padding: 2.5rem 1.25rem 1.25rem;\n  margin: 1.5rem 0;\n  overflow-x: auto;\n  font-size: 0.875rem;\n  line-height: 1.6;\n  box-shadow: var(--shadow-lg);\n}\n\n.post-content .highlight::before {\n  content: '';\n  position: absolute;\n  top: 0.875rem;\n  left: 1.25rem;\n  width: 0.625rem;\n  height: 0.625rem;\n  border-radius: 50%;\n  background: var(--color-code-red);\n  box-shadow:\n    1rem 0 0 var(--color-code-yellow),\n    2rem 0 0 var(--color-code-green);\n}\n\n.post-content pre code,\n.post-content .highlight code {\n  background: transparent;\n  color: #e2e8f0;\n  padding: 0;\n  border: none;\n  word-break: normal;\n}\n\n.post-content hr {\n  border: none;\n  height: 1px;\n  background: linear-gradient(90deg, transparent, var(--color-border), transparent);\n  margin: 2.5rem 0;\n}\n\n.post-content a {\n  font-weight: 500;\n  border-bottom: 1px solid rgba(2, 135, 96, 0.25);\n  transition: border-color var(--transition-fast), color var(--transition-fast);\n}\n\n.post-content a:hover {\n  border-bottom-color: var(--color-primary);\n}\n\n.post-content mark,\n.post-content .post-highlight {\n  background: linear-gradient(180deg, rgba(2, 135, 96, 0.15) 0%, rgba(2, 135, 96, 0.1) 100%);\n  color: var(--color-text);\n  padding: 0.125em 0.25em;\n  border-radius: 2px;\n  font-style: normal;\n}\n\n/* ---------- Reading Progress Bar ---------- */\n.reading-progress-container {\n  position: fixed;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 3px;\n  z-index: 101;\n  background: transparent;\n  /* contain: strict — this element has no visible content and no children\n     that affect layout outside. Tells the browser it can skip all\n     style/layout recalculation for this subtree during scroll. */\n  contain: strict;\n}\n\n.reading-progress-bar {\n  height: 100%;\n  width: 100%;\n  background: linear-gradient(90deg, var(--color-primary), var(--color-accent));\n  /* Removed box-shadow on mobile — fixed element + box-shadow forces\n     per-frame Paint on scroll, which is expensive on low-end GPUs */\n  transition: opacity 0.3s ease;\n  opacity: 0;\n  border-radius: 0 2px 2px 0;\n  transform-origin: left center;\n  transform: scaleX(0);\n  /* No will-change here — added via JS only during scroll to avoid persistent compositing layer */\n}\n\n/* Desktop+: add subtle glow (affordable on desktop GPU) */\n@media (min-width: 768px) {\n  .reading-progress-bar {\n    box-shadow: 0 0 8px rgba(2, 135, 96, 0.35);\n  }\n}\n\n.reading-progress-bar.is-scrolling {\n  will-change: transform;\n}\n\n/* ---------- Post Footer ---------- */\n.post-footer {\n  margin-top: 1rem;\n  padding-bottom: 0;\n}\n\n.post-divider {\n  height: 1px;\n  background: linear-gradient(90deg, transparent, var(--color-border), transparent);\n  margin-bottom: 0.75rem;\n}\n\n/* ---------- WeChat Share ---------- */\n.share-section {\n  display: none;\n  margin-bottom: 1.25rem;\n}\n\n.share-btn {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.5rem;\n  padding: 0.625rem 1.25rem;\n  font-size: 0.875rem;\n  font-weight: 600;\n  color: var(--color-primary);\n  background: rgba(2, 135, 96, 0.08);\n  border: 1px solid rgba(2, 135, 96, 0.2);\n  border-radius: var(--radius-full);\n  cursor: pointer;\n  transition: background var(--transition-fast), transform var(--transition-fast), box-shadow var(--transition-fast);\n}\n\n.share-btn:hover {\n  background: rgba(2, 135, 96, 0.14);\n  box-shadow: var(--shadow-sm);\n}\n\n.share-btn.is-active {\n  background: var(--color-primary);\n  color: #fff;\n  border-color: var(--color-primary);\n}\n\n.share-icon {\n  font-size: 1rem;\n  line-height: 1;\n}\n\n.share-qrcode {\n  display: none;\n  margin-top: 1rem;\n  padding: 1.25rem;\n  background: var(--color-surface);\n  border: 1px solid var(--color-border-light);\n  border-radius: var(--radius-md);\n  text-align: center;\n  box-shadow: var(--shadow-sm);\n  animation: fadeInUp 0.3s ease-out both;\n}\n\n.share-qrcode.is-open {\n  display: inline-block;\n}\n\n.share-qrcode canvas,\n.share-qrcode img {\n  display: block;\n  margin: 0 auto;\n  border-radius: 6px;\n}\n\n.share-qrcode-hint {\n  margin: 0 0 0.75rem;\n  font-size: 0.8125rem;\n  color: var(--color-text-muted);\n}\n\n@media (min-width: 768px) {\n  .share-section {\n    display: block;\n  }\n}\n\n.back-link,\n.back-link:link,\n.back-link:visited,\n.back-link:hover,\n.back-link:active,\n.back-link:focus {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.375rem;\n  font-size: 0.9375rem;\n  font-weight: 600;\n  color: var(--color-text-muted);\n  padding: 0.5rem 0;\n  text-decoration: none !important;\n  border-bottom: none !important;\n  box-shadow: none;\n  transition: color var(--transition-fast), gap var(--transition-fast);\n}\n\n.back-link:hover,\n.back-link:active,\n.back-link:focus {\n  color: var(--color-primary);\n  gap: 0.625rem;\n}\n\n.back-arrow {\n  transition: transform var(--transition-fast);\n}\n\n.back-link:hover .back-arrow {\n  transform: translateX(-3px);\n}\n\n/* <span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class="post-highlight">=\n   Responsive: Tablet (&gt;= 768px)\n   &lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;</span>= */\n@media (min-width: 768px) {\n  :root {\n    --page-padding: 2rem;\n    --content-max-width: 960px;\n  }\n\n  .page-content {\n    padding: 2rem var(--page-padding) 2.5rem !important;\n  }\n\n  .hero {\n    padding: 3.5rem 0 2.5rem;\n  }\n\n  .hero-illustration {\n    max-width: 360px;\n    margin-bottom: 2rem;\n  }\n\n  .hero-title {\n    font-size: 2.75rem;\n  }\n\n  .hero-desc {\n    font-size: 1.125rem;\n  }\n\n  .hero-divider {\n    width: 48px;\n    height: 4px;\n    margin-top: 1.5rem;\n  }\n\n  .tag-filter-bar {\n    margin-top: 1rem;\n  }\n\n  .tag-filter-bar::before {\n    right: 2.25rem;\n    width: 2rem;\n  }\n\n  .tag-filter-inner {\n    gap: 0.5rem;\n    padding-right: 2.5rem;\n  }\n\n  .tag-filter-btn {\n    font-size: 0.8125rem;\n    padding: 0.3125rem 0.75rem;\n  }\n\n  .tag-count {\n    font-size: 0.6875rem;\n  }\n\n  .tag-filter-expand {\n    width: 2rem;\n    height: 2rem;\n  }\n\n  .expand-arrow {\n    font-size: 0.625rem;\n  }\n\n  /* Desktop: switch to column-count masonry for true waterfall layout.\n     Mobile uses CSS Grid which doesn't recalculate during scroll. */\n  .post-grid {\n    display: block;\n    column-count: 2;\n    column-gap: 1.5rem;\n    column-fill: balance;\n    margin-top: 1.5rem;\n    gap: normal;\n  }\n\n  .post-grid .post-card {\n    break-inside: avoid;\n    margin-bottom: 1.5rem;\n  }\n\n  .post-grid.is-single {\n    column-count: 1;\n  }\n\n  .post-card {\n    margin-bottom: 0;\n    border-radius: var(--radius-lg);\n  }\n\n  .post-card-link {\n    padding: 1.75rem;\n  }\n\n  .post-card-title {\n    font-size: 1.25rem;\n    margin-bottom: 0.75rem;\n  }\n\n  .post-card-meta {\n    gap: 0.5rem 0.75rem;\n    margin-bottom: 0.625rem;\n  }\n\n  .post-card-divider {\n    margin: 0 0 1rem;\n  }\n\n  .post-date {\n    font-size: 0.8125rem;\n  }\n\n  .meta-icon {\n    font-size: 0.875rem;\n  }\n\n  .tag-pill {\n    font-size: 0.75rem;\n    padding: 0.25rem 0.625rem;\n  }\n\n  .post-card-excerpt {\n    font-size: 0.875rem;\n    line-height: 1.65;\n    -webkit-line-clamp: 3;\n  }\n\n  .post-card--featured,\n  .post-grid.is-single .post-card {\n    margin-bottom: 1rem;\n\n    .post-card-link { padding: 2rem; }\n    .post-card-title { font-size: 1.5rem; margin-bottom: 0.75rem; }\n    .post-card-divider { margin-bottom: 1rem; }\n    .post-card-excerpt { font-size: 0.9375rem; -webkit-line-clamp: 4; }\n    .post-card-meta { margin-bottom: 0.625rem; }\n    .tag-pill { font-size: 0.75rem; padding: 0.25rem 0.625rem; }\n  }\n\n  .site-footer {\n    margin-top: 4rem;\n    padding: 2.5rem var(--page-padding) !important;\n  }\n\n  .post-header {\n    padding: 2rem 0 1rem;\n    margin-bottom: 1rem;\n  }\n\n  .post-title {\n    font-size: 2.25rem;\n  }\n\n  .post-content {\n    font-size: 1rem;\n    line-height: 1.8;\n  }\n\n  .post-content blockquote {\n    font-size: 0.875rem;\n  }\n\n  .post-content h1 {\n    font-size: 1.75rem;\n  }\n\n  .post-content h2 {\n    font-size: 1.5rem;\n  }\n\n  .post-content h3 {\n    font-size: 1.25rem;\n  }\n\n  .post-content pre,\n  .post-content .highlight {\n    padding: 2.75rem 1.5rem 1.5rem;\n    font-size: 0.9375rem;\n  }\n\n  .post-content .highlight::before {\n    top: 1rem;\n    left: 1.5rem;\n  }\n\n  .empty-state {\n    padding: 5rem 2rem;\n  }\n\n  .empty-illustration {\n    max-width: 340px;\n  }\n}\n\n/* <span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class=\"post-highlight\">=</span><span class="post-highlight">=\n   Responsive: Desktop (&gt;= 1024px)\n   &lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;&lt;span class=\&quot;post-highlight\&quot;&gt;=&lt;/span&gt;</span>= */\n@media (min-width: 1024px) {\n  :root {\n    --page-padding: 2.5rem;\n    --content-max-width: 960px;\n  }\n\n  .page-content {\n    padding: 2.5rem var(--page-padding) 3rem !important;\n  }\n\n  .hero {\n    padding: 4rem 0 3rem;\n  }\n\n  .hero-title {\n    font-size: 3rem;\n  }\n\n  .hero-desc {\n    font-size: 1.25rem;\n  }\n\n  .post-grid {\n    column-gap: 2rem;\n    margin-top: 2rem;\n  }\n\n  .post-grid .post-card {\n    margin-bottom: 2rem;\n  }\n\n  .post-card-link {\n    padding: 2rem;\n  }\n\n  .post-card-title {\n    font-size: 1.375rem;\n  }\n\n  .post-header {\n    padding: 2.5rem 0 1.25rem;\n    margin-bottom: 1.25rem;\n  }\n\n  .post-title {\n    font-size: 2.5rem;\n    margin-bottom: 1.25rem;\n  }\n\n  .post-content {\n    font-size: 1.0625rem;\n    line-height: 1.85;\n  }\n\n  .post-content blockquote {\n    font-size: 0.9375rem;\n  }\n\n  .post-content h1 {\n    font-size: 2rem;\n  }\n\n  .post-content h2 {\n    font-size: 1.625rem;\n  }\n\n  .post-content h3 {\n    font-size: 1.375rem;\n  }\n\n  .post-content pre,\n  .post-content .highlight {\n    padding: 3rem 1.75rem 1.75rem;\n    font-size: 1rem;\n  }\n\n  .post-content .highlight::before {\n    top: 1.125rem;\n    left: 1.75rem;\n  }\n}\n\n/* ---------- Page Layout ---------- */\n.page-header {\n  padding: 1.5rem 0 1.25rem;\n  margin-bottom: 1.5rem;\n  border-bottom: 1px solid var(--color-border-light);\n}\n\n.page-title {\n  font-size: 1.75rem;\n  font-weight: 800;\n  line-height: 1.25;\n  letter-spacing: -0.02em;\n  margin: 0;\n  color: var(--color-text);\n}\n\n.about-illustration {\n  display: block;\n  max-width: 240px;\n  width: 100%;\n  height: auto;\n  margin: 0 auto 2rem;\n}\n\n.page-footer {\n  margin-top: 3rem;\n  padding-bottom: 1rem;\n}\n\n@media (min-width: 768px) {\n  .page-header {\n    padding: 2rem 0 1.5rem;\n    margin-bottom: 2rem;\n  }\n\n  .page-title {\n    font-size: 2.25rem;\n  }\n\n  .about-illustration {\n    max-width: 320px;\n  }\n}\n\n@media (min-width: 1024px) {\n  .page-header {\n    padding: 2.5rem 0 1.75rem;\n    margin-bottom: 2.5rem;\n  }\n\n  .page-title {\n    font-size: 2.5rem;\n  }\n}\n\n/* ---------- Stats Section ---------- */\n.stats-section {\n  margin-top: 1rem;\n  max-width: 100%;\n}\n\n.stats-card {\n  background: var(--color-surface);\n  border-radius: var(--radius-lg);\n  border: 1px solid var(--color-border-light);\n  box-shadow: var(--shadow-md);\n  padding: 0.75rem;\n  display: grid;\n  grid-template-columns: auto 1fr;\n  gap: 0.5rem 0.75rem;\n  align-items: center;\n  transition: transform var(--transition-base), box-shadow var(--transition-base);\n  min-width: 0;\n}\n\n.stats-card:hover {\n  transform: translateY(-2px);\n  box-shadow: var(--shadow-lg);\n}\n\n.stats-header {\n  text-align: center;\n  margin-bottom: 0;\n}\n\n.stats-total {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 0.125rem;\n}\n\n.stats-number {\n  font-size: 1.5rem;\n  font-weight: 800;\n  line-height: 1;\n  background: linear-gradient(135deg, var(--color-primary), var(--color-accent));\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n}\n\n.stats-label {\n  font-size: 0.75rem;\n  font-weight: 500;\n  color: var(--color-text-muted);\n}\n\n.heatmap-wrapper {\n  margin-top: 0;\n}\n\n.heatmap-title {\n  font-size: 0.6875rem;\n  font-weight: 600;\n  color: var(--color-text-secondary);\n  margin: 0 0 0.375rem;\n  text-align: left;\n}\n\n.heatmap-grid {\n  display: grid;\n  grid-template-columns: repeat(12, 1fr);\n  gap: 0.2rem;\n}\n\n.heatmap-cell {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 0.125rem;\n}\n\n.heatmap-block {\n  width: 100%;\n  aspect-ratio: 1;\n  border-radius: 2px;\n  min-height: 10px;\n  transition: transform var(--transition-fast);\n}\n\n.heatmap-cell:hover .heatmap-block {\n  transform: scale(1.15);\n}\n\n.heatmap-label {\n  font-size: 0.5rem;\n  color: var(--color-text-muted);\n  text-align: center;\n  line-height: 1;\n}\n\n.intensity-0 {\n  background: var(--color-border-light);\n}\n\n.intensity-1 {\n  background: rgba(2, 135, 96, 0.3);\n}\n\n.intensity-2 {\n  background: rgba(2, 135, 96, 0.6);\n}\n\n.intensity-3 {\n  background: rgba(2, 135, 96, 0.9);\n}\n\n.heatmap-legend {\n  display: flex;\n  align-items: center;\n  justify-content: flex-start;\n  gap: 0.1875rem;\n  margin-top: 0.375rem;\n}\n\n.legend-label {\n  font-size: 0.5625rem;\n  color: var(--color-text-muted);\n}\n\n.legend-dot {\n  width: 0.5rem;\n  height: 0.5rem;\n  border-radius: 2px;\n}\n\n@media (min-width: 768px) {\n  .stats-card {\n    padding: 2rem;\n    display: block;\n  }\n\n  .stats-header {\n    text-align: center;\n    margin-bottom: 1.5rem;\n  }\n\n  .stats-total {\n    display: inline-flex;\n    flex-direction: row;\n    align-items: baseline;\n    gap: 0.5rem;\n  }\n\n  .stats-number {\n    font-size: 2rem;\n  }\n\n  .stats-label {\n    font-size: 1rem;\n  }\n\n  .heatmap-title {\n    text-align: center;\n    font-size: 0.875rem;\n    margin: 0 0 0.875rem;\n  }\n\n  .heatmap-grid {\n    grid-template-columns: repeat(12, 1fr);\n    gap: 0.625rem;\n  }\n\n  .heatmap-block {\n    min-height: 40px;\n    border-radius: var(--radius-sm);\n  }\n\n  .heatmap-cell {\n    gap: 0.375rem;\n  }\n\n  .heatmap-label {\n    font-size: 0.75rem;\n  }\n\n  .heatmap-legend {\n    justify-content: center;\n  }\n\n  .legend-label {\n    font-size: 0.75rem;\n  }\n\n  .legend-dot {\n    width: 0.75rem;\n    height: 0.75rem;\n  }\n}\n\n@media (min-width: 1024px) {\n  .stats-section {\n    margin-top: 4rem;\n  }\n\n  .stats-card {\n    padding: 2.5rem;\n  }\n}\n\n/* ---------- Mobile: Disable Hover Transitions ----------\n   Mobile has no true hover — :hover fires on touch with 300ms delay.\n   These transitions waste style-recalc time on every tap and add\n   unnecessary paint overhead. Keep transitions only on desktop. */\n@media (max-width: 767px) {\n  a,\n  .tag-pill,\n  .tag-filter-btn,\n  .tag-filter-expand,\n  .back-link,\n  .back-arrow,\n  .post-card,\n  .stats-card,\n  .heatmap-block,\n  .tag-filter-bar::before,\n  .reading-progress-bar {\n    transition: none !important;\n  }\n}\n\n/* ---------- Reduced Motion ---------- */\n@media (prefers-reduced-motion: reduce) {\n  *,\n  *::before,\n  *::after {\n    animation-duration: 0.01ms !important;\n    animation-iteration-count: 1 !important;\n    transition-duration: 0.01ms !important;\n    scroll-behavior: auto !important;\n  }\n\n  .reveal {\n    opacity: 1;\n    transform: none;\n  }\n}\n\n/* ---------- Syntax Highlighting (from minima/Rouge) ----------\n   Extracted from minima's main.css so we can drop the theme dependency entirely.\n   These rules style code blocks generated by Jekyll's Rouge highlighter.\n   Original minima base styles (wrapper, site-nav, footer-col, etc.) are NOT\n   included — they are fully overridden by our custom theme above. */\n.highlight {\n  background: #fff;\n}\n.highlighter-rouge .highlight {\n  background: #eef;\n}\n.highlight .c  { color: #998; font-style: italic; }\n.highlight .err { color: #a61717; background-color: #e3d2d2; }\n.highlight .k  { font-weight: bold; }\n.highlight .o  { font-weight: bold; }\n.highlight .cm { color: #998; font-style: italic; }\n.highlight .cp { color: #999; font-weight: bold; }\n.highlight .c1 { color: #998; font-style: italic; }\n.highlight .cs { color: #999; font-weight: bold; font-style: italic; }\n.highlight .gd { color: #000; background-color: #fdd; }\n.highlight .gd .x { color: #000; background-color: #faa; }\n.highlight .ge { font-style: italic; }\n.highlight .gr { color: #a00; }\n.highlight .gh { color: #999; }\n.highlight .gi { color: #000; background-color: #dfd; }\n.highlight .gi .x { color: #000; background-color: #afa; }\n.highlight .go { color: #888; }\n.highlight .gp { color: #555; }\n.highlight .gs { font-weight: bold; }\n.highlight .gu { color: #aaa; }\n.highlight .gt { color: #a00; }\n.highlight .kc { font-weight: bold; }\n.highlight .kd { font-weight: bold; }\n.highlight .kp { font-weight: bold; }\n.highlight .kr { font-weight: bold; }\n.highlight .kt { color: #458; font-weight: bold; }\n.highlight .m  { color: #099; }\n.highlight .s  { color: #d14; }\n.highlight .na { color: #008080; }\n.highlight .nb { color: #0086B3; }\n.highlight .nc { color: #458; font-weight: bold; }\n.highlight .no { color: #008080; }\n.highlight .ni { color: #800080; }\n.highlight .ne { color: #900; font-weight: bold; }\n.highlight .nf { color: #900; font-weight: bold; }\n.highlight .nn { color: #555; }\n.highlight .nt { color: #000080; }\n.highlight .nv { color: #008080; }\n.highlight .ow { font-weight: bold; }\n.highlight .w  { color: #bbb; }\n.highlight .mf { color: #099; }\n.highlight .mh { color: #099; }\n.highlight .mi { color: #099; }\n.highlight .mo { color: #099; }\n.highlight .sb { color: #d14; }\n.highlight .sc { color: #d14; }\n.highlight .sd { color: #d14; }\n.highlight .s2 { color: #d14; }\n.highlight .se { color: #d14; }\n.highlight .sh { color: #d14; }\n.highlight .si { color: #d14; }\n.highlight .sx { color: #d14; }\n.highlight .sr { color: #009926; }\n.highlight .s1 { color: #d14; }\n.highlight .ss { color: #990073; }\n.highlight .bp { color: #999; }\n.highlight .vc { color: #008080; }\n.highlight .vg { color: #008080; }\n.highlight .vi { color: #008080; }\n.highlight .il { color: #099; }\n"],"file":"style.css"}